 * Remplacement atomique de pointeur simple
 * Un pointeur global est remplacé atomiquement.
 * ========================================================= */
int *ex_ptr = NULL;

void example_atomic_ptr(void) {
    int *old_val = malloc(sizeof(int));
    *old_val = 10;
    ex_ptr = old_val;
    int *new_val = malloc(sizeof(int));
    *new_val = 20;
    __atomic_store_n(&ex_ptr, new_val, __ATOMIC_RELEASE);
    printf("Ancien: %d, Nouveau: %d\n", *old_val, *ex_ptr);
    free(old_val);
    free(new_val);
}
